-- case-studies-specific settings
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Case Studies', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'Client outcomes and transformation stories', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Lead with the client context (anonymized if needed), then the headline outcome with a specific metric. Avoid vague claims."},"content":{"tips":"Structure every case study as: Challenge, Approach, Solution, Results. Quantify outcomes with real metrics. Include a client quote if possible."},"formatting":["Headings: Challenge, Approach, Solution, Results (standard structure)","Tables: before/after metrics, ROI breakdown, timeline","Block quotes: client testimonials and stakeholder quotes","Bold: headline metrics and key outcomes","Bullet lists: deliverables, technologies used, team composition","Numbered lists: implementation phases or milestones"],"avoid":["Vague claims without specific metrics","Naming clients without permission","Missing the Challenge section (context is essential)","Omitting timeline or implementation details"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":15,"max":200},"content":{"min":200,"max":20000},"sourceAi":{"min":1,"max":100}}', datetime('now'));
